// ImageBox.cpp - Custom ImageBox Widget
#include "ImageBox.h"
#include "TodCommon.h"
#include "TodGraphics.h"

ImageBox::ImageBox()
{
    mX = 0;
    mY = 0;
    mWidth = 100;
    mHeight = 100;
    mImage = nullptr;
    mScaleX = 1.0f;
    mScaleY = 1.0f;
    mStretch = false;
}

void ImageBox::Draw(Graphics* g)
{
    if (mImage != nullptr)
    {
        if (mStretch)
        {
            float scaleX = (float)mWidth / mImage->GetWidth();
            float scaleY = (float)mHeight / mImage->GetHeight();
            TodDrawImageScaledF(g, mImage, (float)mX, (float)mY, scaleX, scaleY);
        }
        else
        {
            TodDrawImageScaledF(g, mImage, (float)mX, (float)mY, mScaleX, mScaleY);
        }
    }
}

