// ImageBox.h - Custom ImageBox Widget
#pragma once

#include "Widget.h"
#include "Graphics.h"
#include "Image.h"

class ImageBox : public Widget
{
public:
    ImageBox();
    virtual ~ImageBox() {}

    virtual void Draw(Graphics* g) override;

    // Properties
    int mX;
    int mY;
    int mWidth;
    int mHeight;
    Image* mImage;
    float mScaleX;
    float mScaleY;
    bool mStretch;
};
